from dataclasses import dataclassfrom criresviz.common import OPACITYimport json@dataclass(slots=True)class Molecule:    """    Molecular opacity model used to highlight spectral absorption regions.    A ``Molecule`` stores the wavelength intervals where a molecular species    produces significant opacity, together with the physical conditions used    to generate the opacity model.    """        name: str    active_regions: list    temperature: float    pressure: float    wavelength_range: list    opacity_mode: str    threshold: float    source: str    # properties    # constructors        @classmethod    def from_name(cls, name):        """        Load a molecule from the bundled opacity database.        Parameters        ----------        name : str            Molecule name (e.g. ``"CO"``, ``"H2O"``, ``"CH4"``).        Returns        -------        Molecule            The requested molecular opacity model.        """            with open(OPACITY / f"{name}.json") as f:            data = json.load(f)                return cls(            name=data["species"],            active_regions=[                tuple(region)                for region in data["active_regions"]            ],            temperature=data["temperature"],            pressure=data["pressure"],            wavelength_range=data["wavelength_range"],            opacity_mode=data["opacity_mode"],            threshold=data["threshold"],            source=data["source"],        )        @classmethod    def available(cls):        """        Return the names of all available molecules.            Returns        -------        list[str]            Molecules available in the opacity database.        """        available = [file.stem for file in OPACITY.glob("*.json")]            return available                # dunder methods    def __str__(self):            wmin, wmax = self.wavelength_range            return (            "Molecule\n"            "──────────────────────────────\n"            f"Name:              {self.name}\n"            f"Temperature:       {self.temperature:.0f} K\n"            f"Pressure:          {self.pressure/1e5:.1f} bar\n"            f"Wavelength range:  {wmin:.2f}–{wmax:.2f} μm"        )        